import React from 'react';
import BoxPedido from '../BoxPedido';
import * as C from './style';

function Column({ title, pedidos}) {
    console.log(pedidos);
    return (
        <C.Coluna>
            <C.Titulo>
                {title}            
            </C.Titulo>
            {pedidos.map( e => (<BoxPedido key={e.idpedidos} pedido={e}/>))}
        </C.Coluna>
    )
}

export default Column
